"""
MKT Original Language Commentary — Psalms chapters 55–61
Run: python3 scripts/zc-original-psalms-55-61.py

Key decisions:
- Ps 55:9: ballaʿ/pallag = swallow/split — the Babel-reversal prayer against the enemy's tongues
- Ps 55:12-14: the companion-betrayal (ʾîsh ʿārĕkî / mĕyuddāʿî) mirrors Ps 41:9 → John 13:18
- Ps 55:22: yāhēb = your burden (the God-given load) → 1 Pet 5:7 (cast your anxiety on him)
- Ps 56:8: nôdî/nōʾd wordplay — wandering/wineskin from same root; God storing tears
- Ps 57: ʾal-tashḥêt = "Do Not Destroy" tune title (appears in Pss 57-59, 75)
- Ps 57:8: ʾāʿîrāh hašshaḥar = "I will rouse the dawn" — worshipper rises before sunrise
- Ps 58:3: zōrû rĕshāʿîm mirrāḥem = wicked estranged from the womb — OT original-sin language
- Ps 59:11: "Do not kill them, lest my people forget" — pedagogical divine restraint
- Ps 60:6-8: divine land-oracle with military geography of Canaan
- Ps 61:2: ṣûr yārûm mimmennî = rock too high to climb without divine aid
- Ps 61:6-7: king's life extended + ḥesed/ʾĕmet as appointed guards → Messianic dynasty
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 55–61 — the betrayal-by-companion lament (Ps55),
#   the Gath-setting trust-amid-fear poem (Ps56), the cave-of-Adullam refuge psalm
#   with "I will rouse the dawn" (Ps57), the unjust-rulers imprecation (Ps58), the
#   dogs-circling-city refrain with pedagogical restraint (Ps59), the military-defeat
#   lament with divine land-oracle (Ps60), and the exile-from-ends-of-earth cry with
#   Messianic king-prayer (Ps61).
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(55,62)])"

PSALMS = {
  "55": {
    "1": '<p>Psalm 55 is a Maskil of David — a contemplative or instructional poem (<em>maskîl</em>: from <em>śākal</em>, to understand, to act wisely). The opening plea: <strong>הַאֲזִינָה אֱלֹהִים תְּפִלָּתִי</strong> (<em>haʾăzînāh ʾĕlōhîm tĕpillātî</em>, "Give ear to my prayer, O God") — <em>ʾāzan</em> (hiphil: to give ear, to incline the ear — a physical metaphor of tilting the ear toward the speaker). <strong>וְאַל-תִּתְעַלַּם מִתְּחִנָּתִי</strong> (<em>wĕʾal-titʿallam mittĕḥinnātî</em>, "do not hide yourself from my plea") — <em>ʿālam</em> (hithpael: to hide oneself, to conceal oneself): the same divine self-hiding as <em>hester pānim</em> — the God who could hear but turns away. <em>Tĕḥinnāh</em>: a supplication for grace, a plea for unearned mercy (from <em>ḥānan</em>: to be gracious).</p>',
    "2": '<p><strong>הַקְשִׁיבָה לִּי וַעֲנֵנִי</strong> (<em>haqshîbāh llî waʿănênî</em>, "Pay attention to me and answer me") — <em>qāshab</em> (hiphil: to attend, to prick up the ears): the posture of alert listening. <strong>אָרִיד בְּשִׂיחִי</strong> (<em>ʾārîd bĕśîḥî</em>, "I am troubled in my lament") — <em>rûd</em>: to range about restlessly, to wander without rest (used of Cain in Gen 4:12 — "a fugitive and wanderer shall you be"). <em>Śîaḥ</em>: meditation, musing — the word connotes inward reflection that has become outward complaint (Ps 77:3: "I meditate and my spirit faints"). <strong>וְאָהִימָה</strong> (<em>wĕʾāhîmāh</em>, "and I am agitated") — <em>hāmāh</em>: to roar, to make noise (the same inner tumult of Ps 42:5 — the noisy, turbulent grief).</p>',
    "3": '<p><strong>מִקּוֹל אוֹיֵב</strong> (<em>miqqôl ʾôyêb</em>, "because of the threatening voice of the enemy") — the <em>qôl</em> (voice/sound) of the enemy as a physical threat. <strong>מִפְּנֵי עָקַת רָשָׁע</strong> (<em>mippĕnê ʿāqat rāshāʿ</em>, "from the oppressive presence of the wicked") — <em>ʿāqāh</em>: pressure, oppression (rare — only here and Ps 66:11). <strong>כִּי-יָמִיטוּ עָלַי אָוֶן</strong> (<em>kî-yāmîṭû ʿālay ʾāwen</em>, "for they bring evil upon me") — <em>māṭāh</em> (hiphil: to cause to sway, to make fall, to bring down): the image of tilting a load until it falls — the enemy loading evil onto the Psalmist. <em>ʾĀwen</em>: trouble, harmful intent, iniquity.</p>',
    "4": '<p><strong>לִבִּי יָחִיל בְּקִרְבִּי</strong> (<em>libbî yāḥîl bĕqirbî</em>, "My heart is writhing in anguish within me") — <em>ḥûl</em> (qal: to whirl, to writhe — the word for birth pangs, the churning of labor): the heart in the Psalmist\'s interior churning with the convulsive pain of crisis. <strong>וְאֵימוֹת מָוֶת נָפְלוּ עָלָי</strong> (<em>wĕʾêmôt māwet nāpĕlû ʿālay</em>, "the terrors of death have fallen on me") — <em>ʾêmāh</em>: dread, terror (from the paralyzing terror-root); <em>māwet</em>: death. The "terrors of death" as personified agents that descend on the Psalmist like an ambush.</p>',
    "5": '<p><strong>יִרְאָה וָרַעַד יָבֹא בִי</strong> (<em>yirʾāh wāraʿad yābōʾ bî</em>, "Fear and trembling have come upon me") — <em>yirʾāh</em>: fear (the emotional experience of danger); <em>raʿad</em>: trembling (the physical manifestation). <strong>וַתְּכַסֵּנִי פַּלָּצוּת</strong> (<em>wattĕkassênî pallāṣût</em>, "and shuddering has covered me") — <em>pallāṣût</em>: horror, shuddering (a hapax legomenon — appears only here in the OT). The word suggests a total enveloping of the body in trembling dread — a unique word for a unique extremity of fear.</p>',
    "6": '<p><strong>וָאֹמַר מִי-יִתֶּן-לִי אֵבֶר כַּיּוֹנָה</strong> (<em>wāʾōmar mî-yittĕn-lî ʾêber kayyônāh</em>, "And I said, \'If only I had wings like a dove!\'") — <em>yônāh</em>: a dove — the bird of peace and swift, light flight. The dove-wing fantasy: to be able to rise above the crisis and escape. <strong>אָעוּפָה וְאֶשְׁכֹּנָה</strong> (<em>ʾāʿûpāh wĕʾeshkōnāh</em>, "I would fly away and find rest") — <em>ʿûp</em>: to fly away; <em>shākan</em>: to dwell, to rest (the verb of the <em>Mishkān</em>/Tabernacle). The longing for a place of settled dwelling after the chaos of persecution.</p>',
    "7": '<p><strong>הִנֵּה אַרְחִיק נְדֹד אָלִין בַּמִּדְבָּר</strong> (<em>hinnêh ʾarḥîq nĕdōd ʾālîn bammidbar</em>, "Yes, I would flee far away; I would make my dwelling in the wilderness") — <em>nādad</em>: to flee, to wander (the fugitive\'s flight — Elijah fled to the wilderness in 1 Kgs 19:3-4 with the same impulse: sitting under a broom tree and asking to die). The wilderness (<em>midbar</em>) as the paradoxical refuge — the place of danger is preferred to the dangerous city. <em>Selāh</em> marks the pause on this vision of escape.</p>',
    "8": '<p><strong>אָחִישָׁה מִפְלָט לִי מֵרוּחַ סֹעָה מִסַּעַר</strong> (<em>ʾāḥîshāh miplaṭ lî mêrûaḥ sōʿāh missaʿar</em>, "I would hurry to my refuge from the driving wind and the storm") — <em>ḥûsh</em> (hiphil: to hasten, to make speed): the urgency of the flight. <em>Miplaṭ</em>: a place of escape, a refuge (from <em>pālaṭ</em>: to escape, to slip away). <em>Rûaḥ sōʿāh</em>: a driving/sweeping wind (the storm-force that sweeps everything away); <em>saʿar</em>: a tempest. The metaphor shifts: the enemies are now a tempest that must be outrun.</p>',
    "9": '<p><strong>בַּלַּע אֲדֹנָי פַּלַּג שְׂפָתֵימוֹ</strong> (<em>ballaʿ ʾădōnāy pallag śĕpātêmô</em>, "Confuse them, O Lord; split their tongues apart!") — <em>bālaʿ</em> (piel: to swallow, to confuse/confound — used of God "confounding" the enemies): the Babel-reversal prayer. At Babel, God divided the one language into many (<em>bālal</em>, Gen 11:7); now the Psalmist prays for the same confusion against the enemy\'s coordinated plotting. <em>Pallag śĕpātêmô</em>: "divide/split their lips" — the divided tongue that cannot coordinate, cannot scheme in concert. The enemies\' strength is their unified violent counsel — splitting their speech destroys their collective threat.</p>',
    "10": '<p><strong>יוֹמָם וָלַיְלָה יְסוֹבְבֻהָ עַל-חוֹמֹתֶיהָ</strong> (<em>yômām wālaylāh yĕsôbĕbûhā ʿal-ḥômōtêhā</em>, "Day and night they patrol its walls") — the city\'s walls patrolled not by defenders but by the forces of <em>ʾāwen</em> and <em>ʿāmāl</em>. <strong>וְאָוֶן וְעָמָל בְּקִרְבָּהּ</strong> (<em>wĕʾāwen wĕʿāmāl bĕqirbāh</em>, "iniquity and trouble are entrenched within it") — <em>ʿāmāl</em>: toil, trouble, misery (the word for the crushing labor of oppression). The city that should be protected by soldiers on its walls is instead circled by wickedness and guarded by misery.</p>',
    "11": '<p><strong>הַוּוֹת בְּקִרְבָּהּ</strong> (<em>hawwôt bĕqirbāh</em>, "Ruin is at its center") — <em>hawwāh</em>: destruction, ruin, calamity (only here and a few places — a strong word for violent collapse). <strong>וְלֹא-יָמִישׁ מֵרְחֹבָהּ תֹּךְ וּמִרְמָה</strong> (<em>wĕlōʾ-yāmîsh mêrĕḥōbāh tōk ûmirmāh</em>, "oppression and fraud never leave its public squares") — <em>māyish</em> (hiphil: to remove, to cause to depart): the evil never departs. <em>Tōk</em>: oppression, fraud (rare word, possibly related to crushing); <em>mirmāh</em>: deceit, treachery. The city\'s <em>rĕḥōb</em> (broad open spaces, the marketplace and town square) is dominated by fraud — the public life corrupted throughout.</p>',
    "12": '<p><strong>כִּי לֹא-אוֹיֵב יְחָרְפֵנִי וְאֶשָּׂא</strong> (<em>kî lōʾ-ʾôyêb yĕḥārpênî wĕʾeśśāʾ</em>, "For it is not an enemy who insults me — that I could endure") — <em>ḥārap</em>: to taunt, to reproach. The Psalmist makes the stunning claim: an enemy\'s reproach is bearable — expected, even. <strong>לֹא-מְשַׂנְאִי עָלַי הִגְדִּיל וְאֶסָּתֵר מִמֶּנּוּ</strong> (<em>lōʾ-mĕśanʾî ʿālay higdîl wĕʾessātêr mimmennû</em>, "nor is it someone who hates me who has risen up against me — from that I could hide") — <em>sāthar</em> (niphal: to hide oneself): one can avoid an openly hostile enemy. The betrayal\'s unique anguish: it comes from where defense was impossible because no defense was imagined as necessary.</p>',
    "13": '<p><strong>וְאַתָּה אֱנוֹשׁ כְּעֶרְכִּי</strong> (<em>wĕʾattāh ʾĕnôsh kĕʿerkî</em>, "But it is you — a person like me, my peer") — <em>ʾĕnôsh</em>: a mortal human being (the word emphasizing human frailty); <em>kĕʿerkî</em>: "like my valuation/estimation" — my equivalent, my peer in social standing and worth. <strong>אַלּוּפִי וּמְיֻדָּעִי</strong> (<em>ʾallûpî ûmĕyuddāʿî</em>, "my companion, my close friend") — <em>ʾallûp</em>: a close associate, an intimate companion (originally "chief" but used for a personal confidant); <em>mĕyuddāʿî</em>: my intimate/familiar one (from <em>yādaʿ</em>: the deepest knowing). This is the vocabulary of intimate covenant friendship violated — parallel to Ps 41:9 (ʾîsh shĕlômî / ʾōkêl laḥmî) and to John 13:18.</p>',
    "14": '<p><strong>אֲשֶׁר יַחְדָּו נַמְתִּיק סוֹד</strong> (<em>ʾăsher yaḥdāw namtîq sôd</em>, "We shared deep, sweet counsel together") — <em>mātaq</em> (hiphil: to make sweet, to sweeten); <em>sôd</em>: intimate counsel, the secret of private conversation (the word for the divine council in Jer 23:18 — "who has stood in the counsel of the LORD?"). The shared secret is sweet; its betrayal is correspondingly bitter. <strong>בְּבֵית אֱלֹהִים נְהַלֵּךְ בְּרָגֶשׁ</strong> (<em>bĕbêt ʾĕlōhîm nĕhallêk bĕrāgesh</em>, "together we walked in God\'s house among the festival crowd") — <em>rāgesh</em>: throng, crowd (only here — the festival multitude moving in joyful procession). The betrayal is set against the background of shared worship — the deepest form of covenant fellowship.</p>',
    "15": '<p><strong>יַשִּׁי מָוֶת עֲלֵימוֹ</strong> (<em>yashshî māwet ʿălêmô</em>, "Let death seize them!") — <em>nāshāʾ</em> (or <em>shāʾāh</em>: to deceive, to lead astray — the reading is disputed): "let death ambush/deceive them." <strong>יֵרְדוּ שְׁאוֹל חַיִּים</strong> (<em>yêrĕdû shĕʾôl ḥayyîm</em>, "let them go down to Sheol alive") — the most intense imprecation: descent to Sheol while still living — the fate of Korah and his rebellion (Num 16:30-33: "the earth opened its mouth and swallowed them up... and they went down alive into Sheol"). The imprecation invokes the Korah precedent as the appropriate judgment for covenant betrayal.</p>',
    "16": '<p><strong>אֲנִי אֶל-אֱלֹהִים אֶקְרָא</strong> (<em>ʾănî ʾel-ʾĕlōhîm ʾeqrāʾ</em>, "As for me, I will call upon God") — the decisive "I" (<em>ʾănî</em>) that counters the "they." The structural pivot: the enemies seek the Psalmist\'s death; the Psalmist calls upon God. <strong>וַיהוָה יוֹשִׁיעֵנִי</strong> (<em>waYHWH yôshîʿênî</em>, "and the LORD will rescue me") — <em>yāshaʿ</em> (hiphil: to rescue, to save): the confident future claim in the face of present danger. The trust is not a feeling but a theological claim: YHWH is the one who saves.</p>',
    "17": '<p><strong>עֶרֶב וָבֹקֶר וְצָהֳרַיִם אָשִׂיחָה וְאֶהֱמֶה</strong> (<em>ʿereb wābōqer wĕṣāhŏrayim ʾāśîḥāh wĕʾehĕmeh</em>, "Evening and morning and at noon I cry out my lament and sigh") — the three times of daily prayer: evening, morning, noon. Daniel prays at these same three times (Dan 6:10 — three times daily with windows open toward Jerusalem). This verse suggests a pre-Danielic practice of structured daily prayer in which the Psalmist maintains continuous covenant communion even in crisis. <em>Ʃîaḥ</em> (lament-meditation) and <em>hāmāh</em> (inner sighing-roaring): both complaint and release. <strong>וַיִּשְׁמַע קוֹלִי</strong> (<em>wayyishmaʿ qôlî</em>, "and he hears my voice") — the confident present-tense hearing: not "he will hear" but "he hears" — the continuous divine attention.</p>',
    "18": '<p><strong>פָּדָה בְשָׁלוֹם נַפְשִׁי מִקֲּרָב-לִי</strong> (<em>pādāh bĕshālôm napshî miqqĕrab-lî</em>, "He ransoms me safely from the battle I am in") — <em>pādāh</em>: to ransom, to redeem (the redemption vocabulary of Exod 6:6 — God ransoming Israel from Egypt). <em>Bĕshālôm</em>: in wholeness, in peace — ransomed with no part missing. <strong>כִּי-בְרַבִּים הָיוּ עִמָּדִי</strong> (<em>kî-bĕrabbîm hāyû ʿimmādî</em>, "for they are many who oppose me") — the many-to-one odds that make the divine rescue more remarkable: the LORD against the many, on behalf of the one.</p>',
    "19": '<p><strong>יִשְׁמַע אֵל וְיַעֲנֵם</strong> (<em>yishmaʿ ʾêl wĕyaʿănêm</em>, "God will hear and afflict them") — <em>ʿānāh</em> (piel: to afflict, to oppress — the same word used of Egypt\'s affliction of Israel in Exod 1:11). <strong>וְיֹשֵׁב קֶדֶם סֶלָה</strong> (<em>wĕyōshêb qedem selāh</em>, "the one who is enthroned from of old") — <em>qedem</em>: the ancient time, the primordial past: God enthroned from of old — the eternal divine sovereignty that makes the judge\'s verdict certain. <strong>אֲשֶׁר אֵין חֲלִיפוֹת לָמוֹ</strong> (<em>ʾăsher ʾên ḥălîpôt lāmô</em>, "because they show no sign of change") — <em>ḥălîpāh</em>: a change, an exchange, an alternation: the enemies have no <em>ḥălîpôt</em> (no changes, no repentance). The hardened heart as the condition that makes judgment inevitable.</p>',
    "20": '<p><strong>שָׁלַח יָדָיו בִּשְׁלֹמָיו</strong> (<em>shālaḥ yādāyw bishĕlōmāyw</em>, "He raised his hand against those at peace with him") — the subject returns to the betrayer of vv12-14: the one who "stretched out his hand" against <em>shĕlōmāyw</em> (those who were in covenant-peace with him). <strong>חִלֵּל בְּרִיתוֹ</strong> (<em>ḥillêl bĕrîtô</em>, "he broke his covenant") — <em>ḥālal</em> (piel: to profane, to desecrate): not merely breaking a contract but desecrating the sacred bond of covenant (<em>bĕrît</em>). The covenant-violation as a sacrilegious act.</p>',
    "21": '<p><strong>חָלְקוּ מַחֲמָאֹת פִּיו</strong> (<em>ḥāqĕlû maḥămāʾōt pîw</em>, "His words were smoother than butter") — <em>māḥāʾ/maḥămāʾōt</em>: butter (the sense of soft, smooth richness — from <em>mōʾ/ḥāmāʾ</em>, fresh cream). <em>Ḥālaq</em> (qal: to be smooth, to be slippery): smooth speech as the weapon of deception (the same root as <em>ḥelqāh</em> — smooth ground, flattery). <strong>וּקְרָב לִבּוֹ</strong> (<em>ûqĕrāb libbô</em>, "yet war was in his heart") — the lethal contrast: the exterior is butter; the interior is war (<em>qĕrāb</em>: battle, combat). <strong>רַכּוּ דְבָרָיו מִשֶּׁמֶן</strong> (<em>rakkû dĕbārāyw mishshemen</em>, "his speech was softer than oil") — <em>shemen</em>: olive oil — the liquid that smooths and soothes. <strong>וְהֵמָּה פְתִחוֹת</strong> (<em>wĕhêmmāh pĕtîḥôt</em>, "but they were drawn swords") — <em>pāttaḥ</em> (pual: drawn/unsheathed): the soft speech concealing the drawn blade — the most dangerous enemy is the one who attacks with gentleness.</p>',
    "22": '<p><strong>הַשְׁלֵךְ עַל-יְהוָה יְהָבְךָ</strong> (<em>hashlêk ʿal-YHWH yĕhābĕkā</em>, "Throw your burden onto the LORD") — <em>shālak</em> (hiphil imperative: to throw, to cast): a decisive physical action — the violent tossing of a burden. <em>Yĕhāb</em>: your burden (a rare word — found also in the Aramaic cognate, meaning what is given/assigned to you: your God-given portion, even when it is heavy). The command is not "trust" but "throw" — a more active, urgent gesture. <strong>וְהוּא יְכַלְכְּלֶךָ</strong> (<em>wĕhûʾ yĕkalkĕlekā</em>, "and he will sustain you") — <em>kûl</em> (pilpel: to sustain, to provide for, to bear up): the same word used of Joseph sustaining his family (Gen 47:12). Peter cites this verse in 1 Pet 5:7: "casting all your anxiety on him, because he cares for you." <strong>לֹא-יִתֵּן לְעוֹלָם מוֹט לַצַּדִּיק</strong> (<em>lōʾ-yittên lĕʿôlām môṭ laṣṣaddîq</em>, "he will never let the righteous be shaken") — <em>māṭ</em>: to totter, to slip — the righteous one preserved from the instability that threatens.</p>',
    "23": '<p><strong>וְאַתָּה אֱלֹהִים תּוֹרִדֵם לִבְאֵר שַׁחַת</strong> (<em>wĕʾattāh ʾĕlōhîm tôrîdêm libʾêr shaḥat</em>, "But you, O God, will bring them down into the pit of ruin") — <em>bĕʾêr shaḥat</em>: the pit of destruction (the Sheol imagery — the underground pit that swallows the wicked). <strong>אַנְשֵׁי דָמִים וּמִרְמָה</strong> (<em>ʾanshê dāmîm ûmirmāh</em>, "men of bloodshed and treachery") — the double accusation: violent and deceitful. <strong>לֹא-יֶחֱצוּ יְמֵיהֶם</strong> (<em>lōʾ-yeḥĕṣû yĕmêhem</em>, "will not live out half their days") — <em>ḥāṣāh</em>: to halve, to divide in two: cut off in the middle of life. <strong>וַאֲנִי אֶבְטַח-בָּךְ</strong> (<em>waʾănî ʾebṭaḥ-bāk</em>, "but I — I will trust in you") — the emphatic personal pronoun (<em>wāʾănî</em>: but as for me) contrasting the fate of the wicked with the security of the trusting one. The psalm ends with the naked word of trust: <em>bāṭaḥ</em>.</p>',
  },
  "56": {
    "1": '<p>The superscription places Psalm 56 in the historical narrative of David\'s capture by the Philistines at Gath (1 Sam 21:10-15), where he feigned madness before Achish to escape. <strong>יוֹנַת אֵלֶם רְחֹקִים</strong> (<em>yônat ʾêlem rĕḥōqîm</em>, "Dove of the Distant Oaks" or "Dove of the Distant Silences") — the tune title: <em>yônāh</em> (dove); <em>ʾêlem</em>: the silent/dumb ones, or the oaks (ambiguous in Hebrew); <em>rĕḥōqîm</em>: the distant/faraway ones. The tune evokes separation and longing. <strong>מִכְתָּם</strong> (<em>miktām</em>): a poem-type whose exact meaning is uncertain — possibly "golden poem" or "writing of David." <strong>חָנֵּנִי אֱלֹהִים כִּי-שְׁאָפַנִי אֱנוֹשׁ</strong> (<em>ḥonnênî ʾĕlōhîm kî-shĕʾāpanî ʾĕnôsh</em>, "Be merciful to me, O God, for men are trampling on me") — <em>shāʾap</em>: to trample, to pant after (as a predator pants after prey) — the sense of being relentlessly hunted.</p>',
    "2": '<p><strong>שֹׁאֲפַי כָּל-הַיּוֹם</strong> (<em>shōʾăpay kol-hayyôm</em>, "my enemies trample on me all day long") — <em>shāʾap</em> (piel: to pant after, to trample): the continuous relentless assault — no pause, no reprieve. <strong>כִּי-רַבִּים לֹחֲמִים לִי מָרוֹם</strong> (<em>kî-rabbîm lōḥămîm lî māhôm</em>, "for many are arrayed against me proudly") — <em>māhôm</em>: from on high, proudly (or: "with arrogance"). The numerical and attitudinal disparity: many against one, and they are proud of it.</p>',
    "3": '<p><strong>יוֹם אִירָא אֲנִי אֵלֶיךָ אֶבְטָח</strong> (<em>yôm ʾîrāʾ ʾănî ʾêlêkā ʾebṭāḥ</em>, "When I am afraid, I will put my trust in you") — the pattern of the Psalter: fear acknowledged and then redirected. <em>ʾĀrêʾ</em> (qal imperfect/jussive: "when I am afraid" — a conditional): the fear is real and not denied. <em>Bāṭaḥ</em>: the pivot — at the moment of fear, the action of trust begins. The verse is a compressed theology of faith: not the absence of fear but the act of trust amid fear.</p>',
    "4": '<p><strong>בֵּאלֹהִים אֲהַלֵּל דְּבָרוֹ</strong> (<em>bêʾlōhîm ʾăhallêl dĕbārô</em>, "In God — whose word I praise") — <em>dābār</em>: the divine word (<em>dēbār</em>) as the object of praise. The word "I praise" God\'s word even before the deliverance comes — praising the promise as if it were already fulfilled. <strong>בֵּאלֹהִים בָּטַחְתִּי לֹא אִירָא</strong> (<em>bêʾlōhîm bāṭaḥtî lōʾ ʾîrāʾ</em>, "in God I trust; I will not be afraid") — the trust eliminates the fear. <strong>מַה-יַּעֲשֶׂה בָשָׂר לִי</strong> (<em>māh-yaʿăśeh bāśār lî</em>, "what can a mere mortal do to me?") — <em>bāśār</em>: flesh — the word for mortal, perishable humanity. The contrast: God (eternal, powerful) against <em>bāśār</em> (transient flesh). Paul echoes this logic in Rom 8:31: "If God is for us, who can be against us?"</p>',
    "5": '<p><strong>כָּל-הַיּוֹם דְּבָרַי יְעַצֵּבוּ</strong> (<em>kol-hayyôm dĕbāray yĕʿaṣṣêbû</em>, "All day long they distort my words") — <em>ʿāṣab</em> (piel: to pain, to hurt — here: to twist, to torture words): the enemies take the Psalmist\'s speech and deform it into something harmful. <strong>עָלַי כָּל-מַחְשְׁבֹתָם לְרָעָה</strong> (<em>ʿālay kol-maḥshĕbōtām lĕrāʿāh</em>, "all their scheming against me is for evil") — <em>ḥāshab</em>: to reckon, to devise — the deliberate calculation of evil (the accounting word of Ps 32:2, now applied to malicious planning).</p>',
    "6": '<p><strong>יָגוּרוּ יִצְפֹּנוּ הֵמָּה עֲקֵבַי יִשְׁמֹרוּ</strong> (<em>yāgûrû yiṣpōnû hêmmāh ʿăqêbay yishmōrû</em>, "They gather themselves to stir up trouble, they lie in ambush, they track my steps") — <em>gûr</em>: to sojourn/to stir (here: to conspire together); <em>ṣāpan</em> (qal: to hide, to lie in ambush); <em>ʿāqēb</em>: heel (tracking step by step — literally watching the heels as a stalker follows the last visible footfall). <strong>כַּאֲשֶׁר קִוּוּ נַפְשִׁי</strong> (<em>kaʾăsher qiwwû napshî</em>, "as they wait to take my life") — <em>qāwāh</em> (piel: to wait for, to lie in wait): the predator\'s patient anticipation of the fatal moment.</p>',
    "7": '<p><strong>עַל-אָוֶן פַּלֶּט-לָמוֹ</strong> (<em>ʿal-ʾāwen palleṭ-lāmô</em>, "For their crime, should they escape?") — the rhetorical question of justice: the implied answer is no. <strong>בְּאַף עַמִּים הוֹרֵד אֱלֹהִים</strong> (<em>bĕʾap ʿammîm hôrêd ʾĕlōhîm</em>, "In wrath cast down the peoples, O God!") — <em>ʾap</em>: the nostril/anger of God (the heated breath of divine wrath); <em>yārad</em> (hiphil: to bring down, to cast down): the nations brought low in divine anger. The Psalmist appeals to the standard of divine justice against all wickedness, not merely personal vengeance.</p>',
    "8": '<p><strong>נֹדִי סָפַרְתָּה אָתָּה</strong> (<em>nōdî sāpartāh ʾāttāh</em>, "You have recorded my restless wandering") — <em>nôd</em>: wandering, restless movement (the same root as <em>nādad</em> — to flee, to wander in exile). <em>Sāpar</em>: to count, to number, to record. <strong>שִׂימָה דִמְעָתִי בְנֹאדֶךָ</strong> (<em>śîmāh dimʿātî bĕnōʾdekā</em>, "store my tears in your wineskin") — <em>nōʾd</em>: a wineskin/leather bottle — crucially, the same root as <em>nôd</em> (wandering). The Hebrew plays on the identity: my wandering (<em>nōdî</em>) → your wineskin (<em>nōʾdekā</em>). God stores the wandering in a bottle of wandering — the tears of exile kept in the vessel of exile itself. <strong>הֲלֹא בְּסִפְרָתֶךָ</strong> (<em>hălōʾ bĕsiprātekā</em>, "are they not written in your book?") — God\'s <em>sêper</em> (book/scroll): the divine record of each tear, each displacement. Compare the book of remembrance in Mal 3:16.</p>',
    "9": '<p><strong>אָז יָשׁוּבוּ אוֹיְבַי אָחוֹר</strong> (<em>ʾāz yāshûbû ʾôyĕbay ʾāḥôr</em>, "On the day I call out, my enemies will turn back") — <em>shûb ʾāḥôr</em>: to turn back, to retreat (the reversal of the enemy\'s advance). <strong>בְּיוֹם אֶקְרָא</strong> (<em>bĕyôm ʾeqrāʾ</em>): the decisive "day of calling" — when the Psalmist cries out, the enemy turns. The causative link: the prayer itself is the force that reverses the enemy\'s momentum. <strong>זֶה-יָדַעְתִּי כִּי-אֱלֹהִים לִי</strong> (<em>zeh-yādaʿtî kî-ʾĕlōhîm lî</em>, "this I know: God is on my side") — <em>lî</em>: for me, on my side. The confident <em>yādaʿtî</em> (I know — the covenantal knowledge): the certainty is grounded not in circumstances but in the character of God.</p>',
    "10": '<p><strong>בֵּאלֹהִים אֲהַלֵּל דָּבָר</strong> (<em>bêʾlōhîm ʾăhallêl dābār</em>, "In God — whose word I praise") — the first half of the refrain from v4. <strong>בַּיהוָה אֲהַלֵּל דָּבָר</strong> (<em>baYHWH ʾăhallêl dābār</em>, "in the LORD — whose word I praise") — the refrain doubled with the covenant name YHWH added: in v4, the divine name was <em>ʾĕlōhîm</em>; here both names appear. The word (<em>dābār</em>) of both God in his power and YHWH in his covenant relationship is praised — the divine speech is both universal and covenantally particular.</p>',
    "11": '<p><strong>בֵּאלֹהִים בָּטַחְתִּי לֹא אִירָא</strong> (<em>bêʾlōhîm bāṭaḥtî lōʾ ʾîrāʾ</em>, "In God I trust; I will not be afraid") — the refrain of v4 restated: trust eliminates fear. <strong>מַה-יַּעֲשֶׂה אָדָם לִי</strong> (<em>māh-yaʿăśeh ʾādām lî</em>, "What can human beings do to me?") — in v4 it was <em>bāśār</em> (flesh); here it is <em>ʾādām</em> (human being). The two words for human mortality and finitude bracket the enemy\'s power: what can flesh (<em>bāśār</em>) do? What can a human (<em>ʾādām</em>) do? The God who transcends both renders both powerless.</p>',
    "12": '<p><strong>עָלַי אֱלֹהִים נְדָרֶיךָ</strong> (<em>ʿālay ʾĕlōhîm nĕdārêkā</em>, "I have vows upon me to you, O God") — <em>neder</em>: a vow (the binding promise made to God in a crisis, to be fulfilled upon deliverance — Ps 50:14; Jonah 2:9). <strong>אֲשַׁלֵּם תּוֹדֹת לָךְ</strong> (<em>ʾăshallêm tôdōt lāk</em>, "I will fulfill them; I will offer you my thanksgiving") — <em>shālam</em> (piel: to complete, to pay in full — the wholeness-root); <em>tôdāh</em>: thanksgiving, the thank-offering (the sacrifice of praise — Lev 7:12-15).</p>',
    "13": '<p><strong>כִּי הִצַּלְתָּ נַפְשִׁי מִמָּוֶת</strong> (<em>kî hiṣṣaltā napshî mimmāwet</em>, "For you have delivered my soul from death") — <em>nāṣal</em> (hiphil: to snatch away, to rescue — as from the jaws of a predator): the rescue is a snatching, a sudden saving movement. <strong>הֲלֹא רַגְלַי מִדֶּחִי</strong> (<em>hălōʾ raglî middĕḥî</em>, "yes, my feet from stumbling") — <em>deḥî</em>: stumbling, a slip (from <em>dāḥāh</em>: to push, to trip): the foot rescued before the fatal fall. <strong>לְהִתְהַלֵּךְ לִפְנֵי אֱלֹהִים בְּאוֹר הַחַיִּים</strong> (<em>lĕhithallêk lipnê ʾĕlōhîm bĕʾôr haḥayyîm</em>, "so that I may walk before God in the light of the living") — <em>ʾôr haḥayyîm</em>: "the light of the living" — life as light, death as darkness; to live before God is to walk in the divine luminosity that belongs to the living (contrast Job 3:16 where the stillborn "never see the light"). The rescue from death is the rescue into light.</p>',
  },
  "57": {
    "1": '<p>Psalm 57 carries the superscription <strong>אַל-תַּשְׁחֵת</strong> (<em>ʾal-tashḥêt</em>, "Do Not Destroy") — a tune title appearing also in Psalms 58, 59, and 75. The historical note: David fleeing Saul and hiding in a cave (1 Sam 22:1 — the cave of Adullam; or 1 Sam 24:3 — the cave at En-Gedi). <strong>חָנֵּנִי אֱלֹהִים חָנֵּנִי</strong> (<em>ḥonnênî ʾĕlōhîm ḥonnênî</em>, "Be merciful to me, O God, be merciful to me!") — the doubled imperative intensifying the plea. <strong>בִּי חָסָיָה נַפְשִׁי</strong> (<em>bî ḥāsāyāh napshî</em>, "for my soul takes refuge in you") — <em>ḥāsāh</em>: to flee for refuge (the fundamental trust-verb of the Psalter). <strong>וּבְצֵל-כְּנָפֶיךָ אֶחְסֶה</strong> (<em>ûbĕṣêl-kĕnāpêkā ʾeḥseh</em>, "in the shadow of your wings I will take shelter") — <em>ṣêl kĕnāpêkā</em>: "the shadow of your wings" — the cherubim wings overshadowing the ark (Exod 25:20; 37:9), or the divine mother-bird brooding over the young (Deut 32:11). The cave hides David physically; the divine wings shelter his <em>nāpesh</em> spiritually.</p>',
    "2": '<p><strong>אֶקְרָא לֵאלֹהִים עֶלְיוֹן</strong> (<em>ʾeqrāʾ lêʾlōhîm ʿelyôn</em>, "I cry out to God Most High") — <em>ʿElyôn</em>: the Most High (the ancient divine title used by Melchizedek in Gen 14:18-20 — the same ʿElyôn that Ps 47:2 crowns as universal king). <strong>לָאֵל גֹּמֵר עָלָי</strong> (<em>lāʾêl gōmêr ʿālay</em>, "to God who completes all for me") — <em>gāmar</em>: to complete, to accomplish, to bring to an end (Ps 138:8: "The LORD will fulfill/complete his purpose for me"). God is the one who brings his purposes to completion — not a God who leaves things half-done. The divine faithfulness expressed as completion of intention.</p>',
    "3": '<p><strong>יִשְׁלַח מִשָּׁמַיִם וְיוֹשִׁיעֵנִי</strong> (<em>yishlah mishshāmayim wĕyôshîʿênî</em>, "He will send from heaven and rescue me") — the rescue dispatched from the heavenly throne — God\'s response to prayer crosses the cosmic distance between heaven and earth. <strong>חֵרַף שֹׁאֲפִי</strong> (<em>ḥêrap shōʾăpî</em>, "he will rebuke the one who tramples me") — the divine rebuke (<em>ḥārap</em>: to taunt, to reproach) directed back at the one who taunts the Psalmist. <em>Selāh</em> — pause on the divine action descending from heaven. <strong>יִשְׁלַח אֱלֹהִים חַסְדּוֹ וַאֲמִתּוֹ</strong> (<em>yishlah ʾĕlōhîm ḥasdô waʾămittô</em>, "God will send his steadfast love and his faithfulness") — <em>ḥesed</em> and <em>ʾĕmet</em> as the two divine envoys sent from heaven: covenant-loyalty and truth/faithfulness as personified agents dispatched to the Psalmist in the cave.</p>',
    "4": '<p><strong>נַפְשִׁי בְּתוֹךְ לְבָאִים אֶשְׁכְּבָה לֹהֲטִים</strong> (<em>napshî bĕtôk lĕbāʾîm ʾeshkĕbāh lōhăṭîm</em>, "My soul is surrounded by lions; I must lie down among those who breathe fire") — <em>lābiʾ</em>: a lion (a poetic/archaic word for the lion — the great predator); <em>lōhăṭîm</em>: the fiery ones, those who devour with flame (from <em>lāhaṭ</em>: to blaze, to consume with fire — the divine fire of Exod 3:2). The enemies are simultaneously lions and fire-breathers — a double predatory force. <strong>בְּנֵי-אָדָם שִׁנֵּיהֶם חֲנִית וְחִצִּים</strong> (<em>bĕnê-ʾādām shinnêhem ḥănît wĕḥiṣṣîm</em>, "human beings whose teeth are spears and arrows") — the mouth-as-weapon: teeth as spears, tongue as sword. The word-weapon cluster (also in Ps 55:21: the sword-speech of the betrayer).</p>',
    "5": '<p><strong>רוּמָה עַל-הַשָּׁמַיִם אֱלֹהִים</strong> (<em>rûmāh ʿal-hashāmayim ʾĕlōhîm</em>, "Be exalted above the heavens, O God!") — the refrain (repeated in v11 and identical to Ps 108:5): <em>rûm</em> (imperative: be high, be exalted!). The prayer is directed at God himself: "Be exalted!" — not merely a statement that God is exalted but a cry for the manifestation of that exaltation. <strong>עַל כָּל-הָאָרֶץ כְּבוֹדֶךָ</strong> (<em>ʿal kol-hāʾāreṣ kĕbôdekā</em>, "let your glory be over all the earth!") — the universal scope: the <em>kābôd</em> of God filling the whole earth (as Isa 6:3: "the whole earth is full of his glory").</p>',
    "6": '<p><strong>רֶשֶׁת הֵכִינוּ לִפְעָמַי</strong> (<em>reshet hêkînû lipʿāmay</em>, "They spread a net for my feet") — <em>reshet</em>: a hunting net (the trapper\'s snare for birds and animals). <em>Pāʿam</em>: a step, a footfall — the net spread at the point where the foot falls. <strong>כָּפַף נַפְשִׁי</strong> (<em>kāpap napshî</em>, "my soul was beaten down") — <em>kāpap</em>: to bow down, to be bent (the noun <em>kippāh</em> from the same root — the bowed head). <strong>כָּרוּ לְפָנַי שִׁיחָה נָפְלוּ בְתוֹכָהּ סֶלָה</strong> (<em>kārû lĕpānay shîḥāh nāpĕlû bĕtôkāh selāh</em>, "they dug a pit in my path, but they themselves have fallen into it") — <em>shîḥāh</em>: a pit (the hunters\' trap). The reversal: the trap-diggers fall into their own trap — the ironic divine justice that appears throughout the Psalter (Ps 35:8; 141:10).</p>',
    "7": '<p><strong>נָכוֹן לִבִּי אֱלֹהִים נָכוֹן לִבִּי</strong> (<em>nākhôn libbî ʾĕlōhîm nākhôn libbî</em>, "My heart is fixed, O God, my heart is firm!") — <em>kûn</em> (niphal: to be established, to be set firm, to be prepared): the resolute inner stability after the storm of lament. The double repetition (<em>nākhôn libbî... nākhôn libbî</em>) is emphatic — the heart firmly established, not wavering. This is the inner reality that makes praise possible. <strong>אָשִׁירָה וַאֲזַמֵּרָה</strong> (<em>ʾāshîrāh waʾăzammêrāh</em>, "I will sing and make melody!") — the double response to the fixed heart: song (<em>shîr</em>) and instrumental praise (<em>zāmar</em>).</p>',
    "8": '<p><strong>עוּרָה כְבוֹדִי עוּרָה הַנֵּבֶל וְכִנּוֹר</strong> (<em>ʿûrāh kĕbôdî ʿûrāh hannêbel wĕkinnôr</em>, "Awake, my honor! Awake, harp and lyre!") — <em>ʿûr</em> (imperative: awake, rouse!): the call to the inner self (<em>kābôd</em> = honor, the soul\'s dignity) and to the instruments. The harp (<em>nêbel</em>: a larger lyre-type) and the lyre (<em>kinnôr</em>: David\'s instrument — 1 Sam 16:23). <strong>אָעִירָה שָּׁחַר</strong> (<em>ʾāʿîrāh shāḥar</em>, "I will rouse the dawn!") — the extraordinary claim: the Psalmist will wake the dawn with his praise — the pre-dawn rising before the sun. This reversal of the natural order (the dawn waking the worshipper) is replaced by the worshipper waking the dawn. The intensity of praise is such that human worship precedes the sunrise — not waiting for light but generating it through praise.</p>',
    "9": '<p><strong>אוֹדְךָ בָעַמִּים אֲדֹנָי</strong> (<em>ʾôdĕkā bāʿammîm ʾădōnāy</em>, "I will give you thanks, O Lord, among the peoples") — <em>ʿammîm</em>: the peoples, the nations. The cave-bound fugitive resolves to praise among the international community — the witness to the nations as the goal of covenant survival. <strong>אֲזַמֶּרְךָ בַּלְאֻמִּים</strong> (<em>ʾăzammĕrĕkā ballĕʾummîm</em>, "I will sing your praise among the nations") — <em>lĕʾummîm</em>: ethnic communities, nations. Paul cites a version of this universal praise in Rom 15:9 (via Ps 18:49): "Therefore I will praise you among the Gentiles." The individual survival of the persecuted one becomes the occasion for universal witness.</p>',
    "10": '<p><strong>כִּי-גָדֹל עַד-שָׁמַיִם חַסְדֶּךָ</strong> (<em>kî-gādōl ʿad-shāmayim ḥasdekā</em>, "For your steadfast love reaches to the heavens") — <em>ḥesed</em> measured in cosmic vertical distance: from earth to sky. <strong>וְעַד-שְׁחָקִים אֲמִתֶּךָ</strong> (<em>wĕʿad-shĕḥāqîm ʾămittekā</em>, "your faithfulness to the skies") — <em>shĕḥāqîm</em>: the gossamer clouds, the high heavens (from <em>shāḥaq</em>: to grind fine — the finest dust that rises highest). <em>ʾĔmet</em> (faithfulness/truth) reaching the very top of the atmosphere. The two divine attributes are not merely large — they are cosmically scaled: as high as the sky is from the earth.</p>',
    "11": '<p>The refrain repeated verbatim from v5: <strong>רוּמָה עַל-הַשָּׁמַיִם אֱלֹהִים עַל כָּל-הָאָרֶץ כְּבוֹדֶךָ</strong> — "Be exalted above the heavens, O God; let your glory be over all the earth!" The refrain closes the psalm as it opened the psalm\'s second half (v5): the prayer for divine exaltation and universal glory frames the personal experience of crisis and rescue. Note that Psalm 57:7-11 is almost identical to Psalm 108:1-5 — the early church\'s practice of assembling liturgical combinations from existing psalm material (a "scissors-and-paste" canonical creativity).</p>',
  },
  "58": {
    "1": '<p>Psalm 58 is a sharp indictment of corrupt judges. The superscription: <strong>אַל-תַּשְׁחֵת</strong> (<em>ʾal-tashḥêt</em>, "Do Not Destroy") — the same tune as Psalms 57 and 59. The opening address: <strong>הַאֻמְנָם אֵלֶם צֶדֶק תְּדַבֵּרוּן</strong> (<em>haʾumnām ʾêlem ṣedeq tĕdabbêrûn</em>, "Do you indeed decree what is right, you rulers?") — <em>ʾêlem</em>: the addressees are either <em>ʾêlîm</em> (gods/mighty ones) or <em>ʾêlem</em> (the silent/mute ones — those who should speak but remain silent on justice). The divine council theme (Ps 82) may be in view: heavenly beings or earthly judges who fail their mandate. <strong>מֵישָׁרִים תִּשְׁפְּטוּ בְּנֵי אָדָם</strong> (<em>mêshārîm tishpĕṭû bĕnê ʾādām</em>, "Do you judge human beings with justice?") — <em>mêshārîm</em>: uprightness, what is straight (from <em>yāshar</em>: straight, right). The judicial standard they are failing.</p>',
    "2": '<p><strong>אַף בְּלֵב עוֹלֹת תִּפְעָלוּן</strong> (<em>ʾap bĕlêb ʿawlōt tipʿālûn</em>, "No — in your heart you devise wrongs") — <em>ʿawlāh</em>: injustice, perversity (the twisted/crooked as opposed to the straight); <em>pāʿal</em>: to work, to do — the judicial injustice is their active labor. <strong>בָּאָרֶץ חֲמַס יְדֵיכֶם תְּפַלֵּסוּן</strong> (<em>bāʾāreṣ ḥāmās yĕdêkem tĕpallêsûn</em>, "your hands administer violence throughout the land") — <em>ḥāmās</em>: violence (the pre-Flood crime of Gen 6:11 — "the earth was full of violence/ḥāmās"); <em>pālas</em> (piel: to weigh out, to balance — as on a scale): the metaphor of justice perverted: instead of weighing out righteousness, the judges are weighing out violence on the scales of justice.</p>',
    "3": '<p><strong>זֹרוּ רְשָׁעִים מֵרָחֶם</strong> (<em>zōrû rĕshāʿîm mêrāḥem</em>, "The wicked are alienated from the womb") — <em>zûr</em>: to be a stranger, to be alienated, to turn aside. <em>Mêrāḥem</em>: "from the womb" (from <em>reḥem</em>: the womb/uterus — the place of origin). The wicked\'s estrangement from righteousness is not learned but congenital — from the very source of their existence. <strong>תָּעוּ מִבֶּטֶן דֹּבְרֵי כָזָב</strong> (<em>tāʿû mibbeten dōbĕrê kāzāb</em>, "from their very birth they go astray, speaking lies") — <em>beten</em>: belly, womb (the inner body); <em>tāʿāh</em>: to wander astray, to err. The newborn already lying — not a developmental disorder but an ontological condition. This is the Psalter\'s closest approach to the doctrine of original sin (alongside Ps 51:5: "I was sinful from birth"). Paul\'s argument in Rom 3:10-18 draws on exactly this Psalter tradition.</p>',
    "4": '<p><strong>חֲמַת-לָמוֹ כִּדְמוּת חֲמַת-נָחָשׁ</strong> (<em>ḥămat-lāmô kidmût ḥămat-nāḥāsh</em>, "Their venom is like the venom of a snake") — <em>ḥēmāh</em>: venom, but also burning rage (the word for both poison and fury): the enemies have poison-anger. <em>Nāḥāsh</em>: the serpent — the animal whose poison is delivered through the mouth, just as the judges deliver injustice through speech. <strong>כְּמוֹ-פֶתֶן חֵרֵשׁ יַאְטֵם אָזְנוֹ</strong> (<em>kĕmô-peten ḥêrêsh yaʾṭêm ʾoznô</em>, "like the deaf cobra that blocks its ear") — <em>peten</em>: the cobra (specifically the spitting cobra); <em>ḥêrêsh</em>: deaf; <em>ʾāṭam</em>: to block, to stop up. The cobra that refuses to hear the charmer — a refusal of the divine appeal to repentance.</p>',
    "5": '<p><strong>אֲשֶׁר לֹא-יִשְׁמַע לְקוֹל מְלַחֲשִׁים</strong> (<em>ʾăsher lōʾ-yishmaʿ lĕqôl mĕlaḥăshîm</em>, "that will not listen to the voice of the charmers") — <em>lāḥash</em>: to whisper, to charm (snake-charming involved whispered incantations); the cobra is deaf to the charmer\'s art. <strong>חוֹבֵר חֲבָרִים מְחֻכָּם</strong> (<em>ḥôbêr ḥăbārîm mĕḥukkām</em>, "no matter how skillfully they do it") — <em>ḥābar</em> (piel: to bind together, to make a spell): the binding-together of magical words; <em>mĕḥukkām</em>: skillfully, with wisdom. The charmer\'s skill is useless against the hardened ear. The image establishes the total moral imperviousness of the wicked judges to divine or prophetic appeal.</p>',
    "6": '<p><strong>אֱלֹהִים הֲרָס-שִׁנֵּימוֹ בְּפִימוֹ</strong> (<em>ʾĕlōhîm hăras-shinnêmô bĕpîmô</em>, "Smash their teeth in their mouths, O God!") — <em>hāras</em>: to break down, to demolish (a construction term — as walls are demolished). The teeth as the instrument of the lions of v4 — the predatory weapon removed. <strong>מַלְתְּעוֹת כְּפִירִים נְתָץ יְהוָה</strong> (<em>maltĕʿôt kĕpîrîm nĕtaṣ YHWH</em>, "tear out the fangs of the young lions, O LORD!") — <em>maltĕʿôt</em>: the great jaw-teeth, the molars (the crushing teeth); <em>kĕpîrîm</em>: young lions in their prime strength. The removal of the judicial predators\' weapons through divine force.</p>',
    "7": '<p><strong>יִמָּאֲסוּ כְמוֹ-מַיִם יִתְהַלְּכוּ-לָמוֹ</strong> (<em>yimmāʾăsû kĕmô-māyim yithalĕkû-lāmô</em>, "Let them drain away like water flowing downhill") — <em>māʾas</em>: to melt away, to dissolve (like snow in the sun); <em>hālak</em>: to walk, to flow away. The enemies dissolved like water on a slope — no remnant, no holding. <strong>יִדְרֹךְ חִצָּיו כְּמוֹ יִתְמֹלָלוּ</strong> (<em>yidrok ḥiṣṣāyw kĕmô yitmōlālû</em>, "when they draw their bows, let their arrows fall harmless") — <em>dārak</em>: to tread, to draw (a bow — the foot on the bow to string it, or the drawing of the arrow); the image of the archer whose arrows become blunt/cut to pieces before they fly.</p>',
    "8": '<p><strong>כְּמוֹ שַׁבְּלוּל תֶּמֶס יַהֲלֹךְ</strong> (<em>kĕmô shabbĕlûl temes yahălōk</em>, "Let them be like a snail that dissolves as it goes") — <em>shabbĕlûl</em>: a snail (a hapax legomenon — appears only here in the entire OT). The snail dissolving as it moves — the trail of moisture that was thought in antiquity to be the snail consuming itself as it traveled. <strong>נֵפֶל אֵשֶׁת בַּל-חָזוּ שָׁמֶשׁ</strong> (<em>nêpel ʾêshet bal-ḥāzû shāmesh</em>, "like a stillborn child that never sees the light of the sun") — <em>nêpel</em>: a miscarriage, a stillborn child (from <em>nāpal</em>: to fall). The stillborn who never opens its eyes to sunlight — complete non-existence. The three images (water, snail, stillborn) together describe total dissolution: the wicked unmade as if they never were.</p>',
    "9": '<p><strong>בְּטֶרֶם יָבִינוּ סִּירֹתֵיכֶם אָטָד</strong> (<em>bĕṭerem yābînû sîrōtêkem ʾāṭād</em>, "Before your cooking pots have felt the heat of the thornwood") — <em>sîr</em>: a cooking pot; <em>ʾāṭād</em>: thornbush, bramble — used for quick-burning fuel. The image: before the thorns even heat the pot (almost instantaneously), the judgment comes — the speed of divine justice against the wicked. <strong>כְּמוֹ-חַי כְּמוֹ-חָרוֹן יִשְׂעָרֶנּוּ</strong> (<em>kĕmô-ḥay kĕmô-ḥārôn yisʿārennû</em>, "both the green and the burning, he will sweep them away") — the storm-wind (<em>saʿar</em>) taking both the living and the hot together — the total, immediate sweep of judgment.</p>',
    "10": '<p><strong>יִשְׂמַח צַדִּיק כִּי-חָזָה נָקָם</strong> (<em>yiśmaḥ ṣaddîq kî-ḥāzāh nāqām</em>, "The righteous will rejoice when they see vengeance carried out") — one of the most difficult verses in the Psalter for modern readers. <em>Nāqām</em>: vengeance, retribution — the vindication of justice through punishment. <em>ʿŊfôd</em>. The righteous person\'s joy is not sadism but the satisfaction of justice finally established — the vindication of the wronged. <strong>פְּעָמָיו יִרְחַץ בְּדַם-הָרָשָׁע</strong> (<em>pĕʿāmāyw yirḥaṣ bĕdam-hārāshāʿ</em>, "they will wash their feet in the blood of the wicked") — a visceral image of total victory (the warrior who walks through the blood of the battlefield — also Rev 19:13-15). The metaphor expresses absolute divine triumph over injustice, not a literal program.</p>',
    "11": '<p><strong>וְיֹאמַר אָדָם אַךְ-פְּרִי לַצַּדִּיק</strong> (<em>wĕyōʾmar ʾādām ʾak-pĕrî laṣṣaddîq</em>, "Then people will say, \'There really is a reward for the righteous\'") — <em>pĕrî</em>: fruit, reward (the fruit as the consequence of the right life). The public acknowledgment (<em>ʾādām</em>: humanity in general) that justice is real — that righteousness is not futile. The psalm\'s final aim: the vindication of justice itself in the public square. <strong>אַךְ יֵשׁ-אֱלֹהִים שֹׁפְטִים בָּאָרֶץ</strong> (<em>ʾak yêsh-ʾĕlōhîm shōpĕṭîm bāʾāreṣ</em>, "truly there is a God who judges the earth") — the cosmic counter-claim to the corrupt human court: above the judges who pervert justice stands the divine Judge who does not. The earth has a Judge.</p>',
  },
  "59": {
    "1": '<p>The superscription places Psalm 59 in the same "Do Not Destroy" (<em>ʾal-tashḥêt</em>) category as Psalms 57-58, with the historical note: Saul sent men to watch David\'s house to kill him (1 Sam 19:11-17 — Michal lowered David through a window to escape). <strong>הַצִּילֵנִי מֵאֹיְבַי אֱלֹהָי</strong> (<em>haṣṣîlênî mêʾōyĕbay ʾĕlōhāy</em>, "Rescue me from my enemies, O my God") — <em>nāṣal</em> (hiphil: to snatch away, to rescue): the urgent rescue from the present danger. <strong>מִמִּתְקוֹמְמַי תְּשַׂגְּבֵנִי</strong> (<em>mimmitqômĕmay tĕśaggĕbênî</em>, "set me beyond the reach of those who rise up against me") — <em>śāgab</em> (piel: to set on high, to make inaccessibly high): a rock-fortress image — placing the Psalmist on a height beyond the reach of those rising against him.</p>',
    "2": '<p><strong>הַצִּילֵנִי מִפֹּעֲלֵי אָוֶן</strong> (<em>haṣṣîlênî mippōʿălê ʾāwen</em>, "Rescue me from those who do evil") — <em>pōʿălê ʾāwen</em>: workers of iniquity/trouble (the phrase appears in Pss 5:5; 6:8; 141:9 — an established formula for those whose occupation is harm). <strong>וּמֵאַנְשֵׁי דָמִים הוֹשִׁיעֵנִי</strong> (<em>ûmêʾanshê dāmîm hôshîʿênî</em>, "save me from men who want my blood") — <em>ʾanshê dāmîm</em>: "men of bloods" — those whose hands are stained with violent bloodshed (the plural <em>dāmîm</em> intensifies: blood upon blood).</p>',
    "3": '<p><strong>כִּי הִנֵּה אָרְבוּ לְנַפְשִׁי</strong> (<em>kî hinnêh ʾārbû lĕnapshî</em>, "For see — they lie in ambush for my life") — <em>ʾārab</em>: to lie in wait, to ambush (as a predator waits in cover). <strong>יָגוּרוּ עָלַי עַזִּים</strong> (<em>yāgûrû ʿālay ʿazzîm</em>, "fierce men are gathering against me") — <em>ʿaz</em>: fierce, strong, harsh. <strong>לֹא-פִשְׁעִי וְלֹא-חַטָּאתִי יְהוָה</strong> (<em>lōʾ-pishʿî wĕlōʾ-ḥaṭṭāʾtî YHWH</em>, "not for any offense or sin of mine, LORD") — the declaration of innocence: not for <em>peshaʿ</em> (rebellious transgression) nor <em>ḥaṭṭāʾt</em> (sin, missing the mark). The two major guilt-terms denied — this is not a deserved persecution.</p>',
    "4": '<p><strong>בְּלִי-עָוֹן יְרֻצוּן וְיִכּוֹנָנוּ</strong> (<em>bĕlî-ʿāwōn yĕruṣûn wĕyikkônānû</em>, "for no fault of mine they have mobilized against me") — <em>ʿāwōn</em>: the third guilt-term (iniquity/perversity — as in Ps 32:2), also denied. <em>Rûṣ</em>: to run, to mobilize quickly; <em>kûn</em> (niphal: to prepare, to establish themselves): the enemies are organized and ready. <strong>עוּרָה לִקְרָאתִי וּרְאֵה</strong> (<em>ʿûrāh liqrāʾtî ûrĕʾêh</em>, "Arouse yourself, come to meet me, and look!") — <em>ʿûr</em> (qal imperative: awake, rouse!) — the same word as Ps 44:23 ("Wake up! Why are you sleeping?"). The emergency summons to divine attention.</p>',
    "5": '<p><strong>וְאַתָּה יְהוָה-אֱלֹהִים צְבָאוֹת</strong> (<em>wĕʾattāh YHWH-ʾĕlōhîm ṣĕbāʾôt</em>, "You are the LORD, God of hosts") — the stacking of divine titles: YHWH (the covenant name) + ʾĕlōhîm (God) + ṣĕbāʾôt (armies/hosts) — the full weight of divine identity invoked. <strong>אֱלֹהֵי יִשְׂרָאֵל הָקִיצָה לִפְקֹד כָּל-הַגּוֹיִם</strong> (<em>ʾĕlōhê yisrāʾêl hāqîṣāh lipqōd kol-haggôyim</em>, "God of Israel — rouse yourself to punish all the nations") — <em>pāqad</em>: to attend to, to visit (in judgment): the God who visits the nations with justice. The scope expands: the crisis of one individual becomes a call for universal divine justice over all nations (<em>kol-haggôyim</em>).</p>',
    "6": '<p><strong>יָשׁוּבוּ לָעֶרֶב יֶהֱמוּ כַכָּלֶב</strong> (<em>yāshûbû lāʿereb yehĕmû kakkāleb</em>, "They return each evening, howling like dogs") — the first occurrence of the distinctive refrain (repeated in v14). <em>Kāleb</em>: dog (not the domestic pet of the modern West but the feral, scavenging pariah dog of the ancient city — dangerous, unclean, unwanted). <em>Hāmāh</em>: to growl, to howl (as in Ps 46:3 — the roaring waters; Ps 55:2 — the agitated heart; here: the howling dog-pack). <strong>וִיסוֹבְבוּ עִיר</strong> (<em>wîsôbĕbû ʿîr</em>, "circling around the city") — the feral dogs circling at night, looking for scraps and opportunity — the enemies who patrol without rest.</p>',
    "7": '<p><strong>הִנֵּה יַבִּיעוּן בְּפִיהֶם</strong> (<em>hinnêh yabbîʿûn bĕpîhem</em>, "Listen — they pour out venom with their mouths") — <em>nābāʿ</em> (hiphil: to bubble up, to pour out like a fountain): the violent pouring of hostile speech. <strong>חֲרָבוֹת בְּשִׂפְתוֹתֵיהֶם</strong> (<em>ḥărābôt bĕśiptôtêhem</em>, "their lips are full of swords") — the mouth-as-weapon image (as in Ps 55:21; 57:4): the tongue a sword, the lips the sword-case from which blades emerge. <strong>כִּי-מִי שֹׁמֵעַ</strong> (<em>kî-mî shōmêaʿ</em>, "for they think, \'Who is going to hear?\'") — the arrogance of those who believe their scheming is undetected: the assumption of divine absence or inattention.</p>',
    "8": '<p><strong>וְאַתָּה יְהוָה תִּשְׂחַק-לָמוֹ</strong> (<em>wĕʾattāh YHWH tiśḥaq-lāmô</em>, "But you, LORD, laugh at them") — <em>śāḥaq</em>: to laugh (the divine laughter of Ps 2:4: "He who sits in the heavens laughs; the LORD holds them in derision"). The contrast: the enemies ask "who hears?" (v7) and the answer is: the LORD — who laughs. <strong>תִּלְעַג לְכָל-גּוֹיִם</strong> (<em>tilʿag lĕkol-gôyim</em>, "you scoff at all the nations") — <em>lāʿag</em>: to mock, to deride. The divine scoff at the pretensions of the nations who think themselves beyond accountability.</p>',
    "9": '<p><strong>עֻזּוֹ אֵלֶיךָ אֶשְׁמֹרָה</strong> (<em>ʿuzzô ʾêlêkā ʾeshmōrāh</em>, "O my Strength, I will watch for you") — textual note: the <em>kĕtîb</em> reads <em>ʿuzzô</em> ("his strength") and the <em>qĕrê</em> reads <em>ʿuzzî</em> ("my strength"). Either way, the Psalmist watches (<em>shāmar</em>: to keep, to guard — or here: to wait watchfully) for the divine strength to appear. <strong>כִּי-אֱלֹהִים מִשְׂגַּבִּי</strong> (<em>kî-ʾĕlōhîm miśgabbî</em>, "for God is my fortress") — <em>miśgāb</em>: the high fortress (as in Ps 46:7 — the YHWH ṣĕbāʾôt refrain: "the God of Jacob is our fortress").</p>',
    "10": '<p><strong>אֱלֹהֵי חַסְדִּי יְקַדְּמֵנִי</strong> (<em>ʾĕlōhê ḥasdî yĕqaddĕmênî</em>, "The God of my steadfast love will come ahead of me") — <em>qādam</em> (piel: to go before, to come ahead of, to meet in advance): God will arrive before the Psalmist needs him — the divine advance-party. <em>Ĥesed</em> as God\'s defining character — "God of my ḥesed" personalizes the covenant: the covenant-loyalty is owned as the Psalmist\'s own possession (as in Ps 23:6). <strong>אֱלֹהִים יַרְאֵנִי בְשֹׁרְרָי</strong> (<em>ʾĕlōhîm yarʾênî bĕshōrĕray</em>, "God will let me look in triumph on my enemies") — <em>rāʾāh</em>: to see; <em>shōrēr</em>: an adversary (watching with hostile intent). God showing the Psalmist the sight of the enemy\'s defeat — the vindication made visible.</p>',
    "11": '<p><strong>אַל-תַּהַרְגֵם פֶּן-יִשְׁכְּחוּ עַמִּי</strong> (<em>ʾal-tahargêm pen-yishkĕḥû ʿammî</em>, "Do not kill them, lest my people forget") — the most theologically remarkable verse in the psalm: the prayer for restraint. The enemies are not to be destroyed outright but kept as a living demonstration of divine justice. <em>Yishkĕḥû</em>: "they forget" — the people would forget the lesson if the enemies disappeared too quickly. The defeated enemy as a living monument to divine judgment, a pedagogical retention for the sake of communal memory. <strong>הֲנִיעֵמוֹ בְחֵילְךָ וְהוֹרִידֵמוֹ</strong> (<em>hănîʿêmô bĕḥêlĕkā wĕhôrîdêmô</em>, "bring them down by your power and humble them") — <em>nûaʿ</em> (hiphil: to make to totter, to shake); <em>yārad</em> (hiphil: to bring low). Shaken and brought low — diminished but not eliminated.</p>',
    "12": '<p><strong>חַטַּאת-פִּימוֹ דְּבַר-שְׂפָתֵימוֹ</strong> (<em>ḥaṭṭat-pîmô dĕbar-śĕpātêmô</em>, "For the sin of their mouths and the words of their lips") — the sin is localized: the mouth, the lips, the speech. <strong>וְיִלָּכְדוּ בִגְאוֹנָם</strong> (<em>wĕyillākĕdû bigĕʾônām</em>, "let them be ensnared in their own pride") — <em>lāḵad</em> (niphal: to be caught, trapped — in a net or trap): the ironic justice of the trap. <em>Gaʾăwāh</em>: pride, arrogance (the swelling up of self). Pride as the snare: the arrogant fall into the trap of their own overconfidence.</p>',
    "13": '<p><strong>כַּלֵּה בְחֵמָה כַּלֵּה וְאֵינֵמוֹ</strong> (<em>kallêh bĕḥêmāh kallêh wĕʾênêmô</em>, "Consume them in your wrath; consume them until they are no more") — <em>kālāh</em> (piel: to bring to completion, to finish — the word used of God finishing the work of creation in Gen 2:1-2): bring them to a complete end. <em>Ḥêmāh</em>: divine rage (the heated wrath). <strong>וְיֵדְעוּ כִּי-אֱלֹהִים מֹשֵׁל בְּיַעֲקֹב לְאַפְסֵי הָאָרֶץ</strong> (<em>wĕyêdĕʿû kî-ʾĕlōhîm mōshêl bĕyaʿăqōb lĕʾapsê hāʾāreṣ</em>, "so that people may know that God rules over Jacob to the ends of the earth") — the goal of the judgment: universal knowledge (<em>yādaʿ</em>) that God reigns over Jacob — and through Jacob, to the ends of the earth (<em>ʾapsê hāʾāreṣ</em>: the furthest limits). The individual\'s deliverance has universal theological purpose.</p>',
    "14": '<p>The refrain appears again (identical to v6): <strong>יָשׁוּבוּ לָעֶרֶב יֶהֱמוּ כַכָּלֶב וִיסוֹבְבוּ עִיר</strong> — "They return each evening, howling like dogs and circling the city." The structural repetition of the refrain within the psalm creates a two-stanza hymn, each stanza moving from the image of the feral dogs (vv6/14) to the Psalmist\'s trust and the divine response. The dogs\' circling is relentless — but the divine response (vv7-13, vv15-17) frames it on both sides.</p>',
    "15": '<p><strong>הֵמָּה יְנִיעוּן לֶאֱכֹל</strong> (<em>hêmmāh yĕnîʿûn leʾĕkōl</em>, "They roam around in search of food") — <em>nûaʿ</em>: to wander, to shake from side to side (the hungry dog\'s restless search). The hungry scavenger as the image of the aimless, unsatisfied enemy. <strong>אִם-לֹא יִשְׂבְּעוּ וַיָּלִינוּ</strong> (<em>ʾim-lōʾ yiśbĕʿû wayyālînû</em>, "they growl when they are not satisfied") — <em>lûn</em>: to pass the night, to spend the night (the dogs not going home — staying out through the dark hours). The unsatisfied growl of the unfed predator who cannot catch what it hunts.</p>',
    "16": '<p><strong>וַאֲנִי אָשִׁיר עֻזֶּךָ</strong> (<em>waʾănî ʾāshîr ʿuzzekā</em>, "But I will sing of your strength") — the emphatic <em>waʾănî</em> (but I!) contrasting the howling dogs with the Psalmist\'s song. <em>ʿŌz</em>: strength. <strong>וַאֲרַנֵּן לַבֹּקֶר חַסְדֶּךָ</strong> (<em>waʾărannên labbōqer ḥasdekā</em>, "I will sing aloud of your steadfast love in the morning") — <em>rānan</em>: to shout for joy (the ringing joyful cry). <em>Labbōqer</em>: in the morning (the dogs prowl through the dark night; the Psalmist greets the morning with praise). <strong>כִּי-הָיִיתָ מִשְׂגָּב לִי</strong> (<em>kî-hāyîtā miśgāb lî</em>, "for you have been my fortress") — <em>miśgāb</em>: the high fortress of Ps 46:7/11 — "the God of Jacob is our miśgāb."</p>',
    "17": '<p><strong>עֻזִּי אֵלֶיךָ אֲזַמֵּרָה</strong> (<em>ʿuzzî ʾêlêkā ʾăzammêrāh</em>, "O my Strength, I will sing praise to you") — the closing verse mirrors v9: the <em>ʿōz</em> (strength) that was watched for is now the strength to which praise is directed. <strong>כִּי-אֱלֹהִים מִשְׂגַּבִּי</strong> (<em>kî-ʾĕlōhîm miśgabbî</em>, "for God is my fortress") — the identical phrase from v9, closing the psalm with the same confession. <strong>אֱלֹהֵי חַסְדִּי</strong> (<em>ʾĕlōhê ḥasdî</em>, "the God who shows me steadfast love") — <em>ḥesed</em> as the final word of the psalm: the covenant loyalty that grounds the strength, the fortress, and the morning song. The dogs howl into the night; the Psalmist praises into the morning.</p>',
  },
  "60": {
    "1": '<p>Psalm 60 is a national lament after military defeat — the Israelite communal parallel to Psalm 44\'s innocent-suffering. The superscription gives a precise historical setting: David\'s war with Aram-naharaim and Aram-zobah, while Joab struck down 12,000 Edomites in the Valley of Salt (cf. 2 Sam 8:13; 1 Chr 18:12 — where 18,000 are listed; the variance may reflect different phases of the campaign or different counting). The tune: "Lily of the Testimony" (<em>shûshan ʿêdût</em>). <strong>אֱלֹהִים זְנַחְתָּנוּ פְרַצְתָּנוּ</strong> (<em>ʾĕlōhîm zĕnaḥtānû pĕraṣtānû</em>, "O God, you have rejected us and broken our defenses") — <em>zānaḥ</em>: the covenant-rejection word (as in Ps 44:9, 23; 43:2). <em>Pāraṣ</em>: to break through, to burst through (as a wall is breached). <strong>אָנַפְתָּ תְשׁוֹבֵב לָנוּ</strong> (<em>ʾānaphtā tĕshôbêb lānû</em>, "you have been angry — restore us!") — <em>ʾānaph</em>: to snort in anger (the heavy, angry breathing); <em>shûb</em> (polel: to restore, to bring back).</p>',
    "2": '<p><strong>הִרְעַשְׁתָּה אֶרֶץ פְּצַמְתָּהּ</strong> (<em>hirʿashtāh ʾereṣ pĕṣamtāhh</em>, "You have made the earth shake; you have cracked it open") — <em>rāʿash</em> (hiphil: to cause to shake — the earthquake verb of Ps 18:7); <em>pāṣam</em>: to split, to crack (rare — the fissure of a broken landscape). The military defeat is described in geological imagery: the land itself fractured. <strong>רְפָה שְׁבָרֶיהָ כִי-מָטָה</strong> (<em>rĕpāh shĕbārêhā kî-māṭāh</em>, "heal its fractures, for it is collapsing") — <em>rāpāʾ</em>: to heal (as in Ps 41:4); <em>māṭāh</em>: to totter (the instability verb of Ps 46:2, 5, 6). The earthquake of defeat needs divine healing.</p>',
    "3": '<p><strong>הִרְאִיתָה עַמְּךָ קָשָׁה</strong> (<em>hirʾîtāh ʿammĕkā qāshāh</em>, "You have put your people through severe trials") — <em>qāsheh</em>: hard, severe (the hardships that prove and test). <strong>הִשְׁקִיתָנוּ יַיִן תַּרְעֵלָה</strong> (<em>hishqîtānû yayin tarʿêlāh</em>, "you have made us drink disorienting wine") — <em>yayin</em>: wine; <em>tarʿêlāh</em>: a staggering, a reeling (from <em>rāʿal</em>: to quake, to tremble — so "wine of reeling/staggering"). God the host serving disorienting wine to his own people — the military confusion of defeat experienced as divine intoxication. The image appears also in Isa 51:17-22: the "cup of staggering" that Jerusalem must drink.</p>',
    "4": '<p><strong>נָתַתָּה לִירֵאֶיךָ נֵס</strong> (<em>nātatā lîrêʾêkā nês</em>, "You have set up a banner for those who fear you") — <em>nês</em>: a standard, a flag-pole, a rallying banner (the military signal for gathering troops — Num 21:8-9 [Moses\' bronze serpent on a <em>nês</em>]; Isa 11:12 [the banner for the nations]). <strong>לְהִתְנוֹסֵס מִפְּנֵי קֹשֶׁט סֶלָה</strong> (<em>lĕhitnôsês mippĕnê qōshet selāh</em>, "for them to rally to in the face of the enemy\'s bow") — <em>nāsas</em> (hithpoel: to be lifted up, to display oneself as a banner): the rallying of those who fear God around the divine standard. Even in defeat, there is a banner to gather around.</p>',
    "5": '<p><strong>לְמַעַן יֵחָלְצוּן יְדִידֶיךָ</strong> (<em>lĕmaʿan yêḥālĕṣûn yĕdîdêkā</em>, "Save your dear ones — rescue them") — <em>yĕdîdîm</em>: the beloved ones, the darlings (the same root as <em>yĕdîdôt</em> of Ps 45 — "Song of Beloved-Ones"): the people as God\'s beloved. <em>ḥālaṣ</em> (niphal: to be rescued, to be delivered). <strong>הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי</strong> (<em>hôshîʿāh yĕmînĕkā waʿănênî</em>, "rescue them by your right hand, and answer our prayer") — <em>yāmîn</em>: the right hand (the hand of power and of honor — the hand that holds the sword and that blesses). The divine right hand as the instrument of salvation.</p>',
    "6": '<p><strong>אֱלֹהִים דִּבֶּר בְּקָדְשׁוֹ</strong> (<em>ʾĕlōhîm dibbêr bĕqodsho</em>, "God has spoken in his holiness") — the oracle begins with the highest possible authority marker: divine speech from the divine holiness itself (<em>qōdesh</em>: the sacred, the set-apart realm). <strong>אֶעְלֹזָה אֲחַלְּקָה שְׁכֶם</strong> (<em>ʾeʿlōzāh ʾăḥallĕqāh shĕkem</em>, "I will triumph; I will divide up Shechem") — <em>ʿālaz</em>: to exult, to triumph; <em>ḥālaq</em> (piel: to divide up, to allocate): the divine warrior dividing the conquered territory. Shechem (the central highland city of Ephraim, Jacob\'s territory — Gen 33:18-19) is the first claimed. <strong>וְעֵמֶק סֻכּוֹת אֲמַדֵּד</strong> (<em>wĕʿêmeq sukkôt ʾămaddêd</em>, "and portion out the Valley of Succoth") — Succoth (east of the Jordan, Jacob\'s camp site in Gen 33:17) measured out — the divine surveyor staking the land.</p>',
    "7": '<p><strong>לִי גִלְעָד וְלִי מְנַשֶּׁה</strong> (<em>lî gilʿād wĕlî mĕnashsheh</em>, "Gilead is mine, Manasseh is mine") — the Transjordanian territory (Gilead) and the half-tribe of Manasseh claimed by the divine warrior. <strong>וְאֶפְרַיִם מָעוֹז רֹאשִׁי</strong> (<em>wĕʾeprayim māʿôz rōʾshî</em>, "Ephraim is my helmet") — <em>māʿôz rōʾshî</em>: "stronghold of my head" — the military-helmet image: Ephraim, the largest and strongest northern tribe, is the divine warrior\'s war-helmet. <strong>יְהוּדָה מְחֹקְקִי</strong> (<em>yĕhûdāh mĕḥōqĕqî</em>, "Judah is my scepter") — <em>mĕḥōqēq</em>: the one who issues decrees, the ruler\'s scepter/staff (from <em>ḥāqaq</em>: to inscribe, to decree). Judah as the ruling tribe — echoing Gen 49:10: "the scepter shall not depart from Judah."</p>',
    "8": '<p><strong>מוֹאָב סִיר רַחְצִי</strong> (<em>mōʾāb sîr raḥṣî</em>, "Moab is my washbasin") — the triumphant humiliation: Moab (Israel\'s trans-Jordan neighbor, perennial enemy) reduced to the washbasin — the vessel used for the most menial cleansing (the basin in which the warrior washes his feet after battle). <strong>עַל-אֱדוֹם אַשְׁלִיךְ נַעֲלִי</strong> (<em>ʿal-ʾĕdôm ʾashlîk naʿălî</em>, "over Edom I throw my sandal") — the sandal-throw as a legal sign of ownership and appropriation (as in Ruth 4:7-8 — the kinsman-redeemer\'s sandal transfer; and Deut 25:9 — the rejected brother\'s sandal removed). Throwing the sandal over Edom: claiming ownership, treating Edom as a footstool. <strong>עָלַי פְּלֶשֶׁת הִתְרוֹעָעִי</strong> (<em>ʿālay pĕleshet hitrôʿāʿî</em>, "over Philistia I shout in triumph") — <em>rûaʿ</em> (hithpael: to raise the victory cry against, to shout in triumph over): the Philistines receive not service (as Moab and Edom) but the shout of conquest.</p>',
    "9": '<p><strong>מִי יֹבִלֵנִי עִיר מָצוֹר</strong> (<em>mî yōbîlênî ʿîr māṣôr</em>, "Who will bring me into the fortified city?") — the oracle of divine ownership (vv6-8) is followed by the community\'s question: how is this divine claim to be actualized? <em>ʿÎr māṣôr</em>: the besieged/fortified city (the Edomite stronghold of Petra — the rock-city?). <strong>מִי נָחַנִי עַד-אֱדוֹם</strong> (<em>mî nāḥanî ʿad-ʾĕdôm</em>, "who will guide me all the way to Edom?") — <em>nāḥāh</em>: to lead, to guide (the shepherd-guide verb of Ps 31:3; 43:3). The way to the conquest requires a divine guide.</p>',
    "10": '<p><strong>הֲלֹא-אַתָּה אֱלֹהִים זְנַחְתָּנוּ</strong> (<em>hălōʾ-ʾattāh ʾĕlōhîm zĕnaḥtānû</em>, "Have you not rejected us, O God?") — the question that restates the opening (v1: <em>zānaḥ</em>): has the God who owns all the territory abandoned his people? The oracle of vv6-8 shows God\'s territorial claim; the military defeat (v1-3) shows the current reality. <strong>וְלֹא-תֵצֵא אֱלֹהִים בְּצִבְאֹתֵינוּ</strong> (<em>wĕlōʾ-têṣêʾ ʾĕlōhîm bĕṣibʾôtênû</em>, "You no longer go out, God, with our armies") — the divine warrior who should march at the head of the armies (as in Num 10:35: "Rise up, LORD! May your enemies be scattered!") is absent. The military defeat is the absence of the divine warrior.</p>',
    "11": '<p><strong>הָבָה-לָּנוּ עֶזְרָת מִצָּר</strong> (<em>hābāh-llānû ʿezrat miṣṣār</em>, "Give us help against the enemy") — <em>hābāh</em>: give (an urgent imperative); <em>ʿezrāh</em>: help (the <em>ʿezer</em> of Gen 2:18 — the helper who is needed). <strong>וְשָׁוְא תְּשׁוּעַת אָדָם</strong> (<em>wĕshāwĕ tĕshûʿat ʾādām</em>, "for human deliverance is worthless") — <em>shāwĕ</em>: vanity, emptiness (the <em>shāwĕ</em> of the Decalogue: "you shall not take the name of the LORD your God in vain/emptiness" — the same emptiness applied to human military capacity). <em>Tĕshûʿat ʾādām</em>: "the salvation of humanity/man" — human military power is as empty as the misuse of the divine name. The psalm\'s entire theological argument: the territory belongs to God (vv6-8), but only God can actualize the claim (vv9-12).</p>',
    "12": '<p><strong>בֵּאלֹהִים נַעֲשֶׂה-חָיִל</strong> (<em>bêʾlōhîm naʿăśeh-ḥāyil</em>, "Through God we will do great deeds") — <em>ḥayil</em>: strength, valor, wealth (the <em>ḥayil</em> of "women of valor" in Prov 31:10 — the same word). The great deeds (<em>ḥāyil</em>) are possible only "through God" (<em>bêʾlōhîm</em>): the prepositional phrase carries the theological weight. <strong>וְהוּא יָבוּס צָרֵינוּ</strong> (<em>wĕhûʾ yābûs ṣārênû</em>, "he himself will crush our enemies") — <em>bûs</em>: to trample underfoot (as the nations were trampled in Ps 44:5; 47:3). The pronoun <em>hûʾ</em> (he himself) is emphatic: not we, not our armies, but God himself will do the treading-down. The psalm of defeat ends on the note of confident divine victory.</p>',
  },
  "61": {
    "1": '<p><strong>שִׁמְעָה אֱלֹהִים רִנָּתִי</strong> (<em>shîmʿāh ʾĕlōhîm rinnātî</em>, "Hear my cry, O God!") — <em>rinnāh</em>: the ringing cry (originally of joy, but in lament psalms: the urgent, piercing cry that demands to be heard — Ps 17:1; 142:6). The difference between <em>tĕpillāh</em> (a measured prayer) and <em>rinnāh</em> (a piercing cry): this is the latter. <strong>הַקְשִׁיבָה תְּפִלָּתִי</strong> (<em>haqshîbāh tĕpillātî</em>, "listen to my prayer") — <em>qāshab</em> (hiphil: to pay attention, to prick up the ears): the two-fold plea: hear the cry and attend to the prayer.</p>',
    "2": '<p><strong>מִקְצֵה הָאָרֶץ אֵלֶיךָ אֶקְרָא</strong> (<em>miqqĕṣeh hāʾāreṣ ʾêlêkā ʾeqrāʾ</em>, "From the ends of the earth I call out to you") — <em>qāṣeh</em>: the end, the edge, the furthest extremity. The prayer of the exile — one who is at the world\'s edge, removed from Jerusalem, distant from the temple. The ends of the earth as both geographical distance and spiritual extremity. <strong>בַּעֲטֹף לִבִּי</strong> (<em>baʿăṭōp libbî</em>, "when my heart grows faint") — <em>ʿāṭap</em>: to grow faint, to languish (as in Ps 142:3 — the spirit overwhelmed). <strong>בְּצוּר-יָרוּם מִמֶּנִּי תַנְחֵנִי</strong> (<em>bĕṣûr-yārûm mimmennî tanḥênî</em>, "lead me to the rock that is higher than I") — <em>ṣûr yārûm mimmennî</em>: "a rock that is too high for me" — the inaccessible cliff, higher than unaided human climbing can reach. Only the divine guide (<em>nāḥāh</em>: to lead) can take the Psalmist to the rock that is beyond human reach. The prayer is not to climb alone but to be led.</p>',
    "3": '<p><strong>כִּי-הָיִיתָ מַחְסֶה לִי</strong> (<em>kî-hāyîtā maḥseh lî</em>, "For you have been a shelter for me") — <em>maḥseh</em>: a refuge, a place of shelter (as in Ps 46:1 — <em>maḥăseh wāʿōz</em>). The past experience of divine shelter grounds the present plea. <strong>מִגְדַּל-עֹז מִפְּנֵי אוֹיֵב</strong> (<em>migdal-ʿōz mippĕnê ʾôyêb</em>, "a strong tower against the enemy") — <em>migdal</em>: a tower (the military watchtower — Prov 18:10: "The name of the LORD is a strong tower; the righteous run into it and are safe"). <em>ʿŌz</em>: strength. The combined image: God as both the low-lying shelter (<em>maḥseh</em>) and the tall strong tower (<em>migdal ʿōz</em>).</p>',
    "4": '<p><strong>אָגוּרָה בְאָהָלְךָ עוֹלָמִים</strong> (<em>ʾāgûrāh bĕʾāhālĕkā ʿôlāmîm</em>, "I will dwell in your tent forever") — <em>gûr</em>: to sojourn, to live as a temporary resident (the alien/pilgrim\'s residency — but here: the permanent dwelling of the covenant member in the divine tent). <em>ʿÔlāmîm</em>: the plural intensification of "forever" — across all the ages. <strong>אֶחְסֶה בְסֵתֶר כְּנָפֶיךָ</strong> (<em>ʾeḥseh bĕsêter kĕnāpêkā</em>, "I will take refuge under the shelter of your wings") — <em>sêter kĕnāpêkā</em>: "the secret place of your wings" — the hiding in the inner shadow of the divine wings (as in Ps 27:5; 31:20 — the "shelter" / <em>sûkkāh</em> of divine protection). <em>Selāh</em>.</p>',
    "5": '<p><strong>כִּי-אַתָּה אֱלֹהִים שָׁמַעְתָּ לִנְדָרָי</strong> (<em>kî-ʾattāh ʾĕlōhîm shāmaʿtā lîndāray</em>, "For you, O God, have heard my vows") — <em>neder</em>: the vow (the binding promise made in crisis, as in Ps 56:12). <strong>נָתַתָּ יְרֻשַּׁת יִרְאֵי שְׁמֶךָ</strong> (<em>nātatā yĕrushshat yirʾê shĕmekā</em>, "you have given me the inheritance of those who fear your name") — <em>yĕrushshāh</em>: inheritance, possession (from <em>yārash</em>: to possess, to inherit — the Conquest vocabulary). The inheritance is the possession of those who fear (<em>yārēʾ</em>) the divine name — the covenant community\'s common inheritance.</p>',
    "6": '<p><strong>יָמִים עַל-יְמֵי-מֶלֶךְ תּוֹסִיף</strong> (<em>yāmîm ʿal-yĕmê-melek tôsîp</em>, "You will extend the king\'s days") — the psalm\'s center of gravity shifts to the king (perhaps the Psalmist himself in his royal capacity, or a priestly prayer for the reigning king). <em>Tôsîp</em> (hiphil: to add, to increase): God adding days to the royal life. <strong>שְׁנוֹתָיו כְּמוֹ-דֹר וָדֹר</strong> (<em>shĕnôtāyw kĕmô-dōr wādōr</em>, "his years shall span many generations") — <em>dōr wādōr</em>: "generation after generation" — the hyperbolic prayer for the royal life extended across multiple human generations. This exceeds any historical king\'s lifespan — pointing toward the eschatological king whose "years endure through all generations" (Ps 102:24). The NT reads this as the eternal life of Christ the King.</p>',
    "7": '<p><strong>יֵשֵׁב עוֹלָם לִפְנֵי אֱלֹהִים</strong> (<em>yêshêb ʿôlām lipnê ʾĕlōhîm</em>, "May he dwell before God forever") — <em>yāshab lipnê ʾĕlōhîm</em>: to sit/dwell before God (the posture of covenant access and royal authority — as in Ps 41:12: "you place me before your face forever"). <em>ʿÔlām</em>: forever. <strong>חֶסֶד וֶאֱמֶת מַן יִנְצְרֻהוּ</strong> (<em>ḥesed weʾĕmet man yinṣĕrûhû</em>, "appoint steadfast love and faithfulness to guard him") — <em>ḥesed</em> and <em>ʾĕmet</em> personified as appointed guards (<em>nāṣar</em>: to keep, to guard — the sentinel\'s task). The same twin divine attributes that are sent as envoys in Ps 57:3 are here assigned as the king\'s personal bodyguard. The prayer: may God\'s own covenant-loyalty and truth stand watch over the king. In the Messianic reading, these are the attributes of the divine Son who is guarded by the Father\'s eternal character.</p>',
    "8": '<p><strong>כֵּן אֲזַמְּרָה שִׁמְךָ לָעַד</strong> (<em>kên ʾăzammĕrāh shimkā lāʿad</em>, "So I will sing praise to your name forever") — <em>lāʿad</em>: forever (a stronger form: "to the perpetuity"). The Psalmist\'s vow: the perpetual praise of the divine <em>shêm</em> (name — the whole person and character of God) in response to the divine keeping promised in v7. <strong>לְשַׁלְּמִי נְדָרַי יוֹם יוֹם</strong> (<em>lĕshallĕmî nĕdāray yôm yôm</em>, "as I fulfill my vows day after day") — <em>shālam</em> (piel: to complete, to pay in full — the wholeness-root); <em>yôm yôm</em>: day after day — the daily rhythm of vow-fulfillment. The psalm that began from the ends of the earth ends in the daily round of praise — exile transformed into liturgy, extremity into regularity.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    for ch in range(55, 62):
        print(f'  ch{ch}: {len(existing.get(str(ch), {}))} verses')
    print('Psalms 55-61 mkt-original written.')

if __name__ == '__main__':
    main()
